// Script Continued Below
var Organization_uiAction = Class.create();
Organization_uiAction.prototype = {
    initialize: function() {
    },

	// STRY0130940 
	canCreateOOO: function(user_sys_id){
		var answer = false;
		var currentUser_sys_id = gs.getUserID();
		var isCurrentUser = currentUser_sys_id == user_sys_id;
		var isTaskAdministrator = gs.getUser().hasRole(
				tasking_System_Settings_Scripts.CONST_ROLE_TASK_ADMINISTRATOR);
		var isTaskManager = 
			new tasking_System_Settings_Scripts().getUserisTaskManagerOfUser(currentUser_sys_id,user_sys_id);
		if(isCurrentUser || isTaskAdministrator || isTaskManager){
			answer=true;
		}
		return answer;
	},

	uiAction_createOoO: function(ooo) {
		ooo.insert();
	},

	uiAction_deleteOoO: function(ooo) {
		ooo.deleteRecord();
	},

	uiAction_ActivateOU: function(ou) {
		ou.active = true;
		ou.update();
	},

	uiAction_DeactivateOU: function(ou) {
		ou.active = false;
		ou.update();		
	},

	uiAction_SaveOU: function(ou) {
		ou.insert();
	},

	uiAction_DeleteMember: function(member) {
		member.deleteRecord();
	},

	uiAction_SaveMember: function(member) {
		member.insert();
	},

	uiAction_SaveContactInfo: function(contact) {
		contact.insert();
	},

    type: 'Organization_uiAction'
};
